func GetNames(users []User) []string {
    var names []string  // BAD: will grow incrementally
    for _, u := range users {
        names = append(names, u.Name)
    }
    return names
}

findings.suggested_fix:
func GetNames(users []User) []string {
    names := make([]string, 0, len(users))  // GOOD: pre-allocated
    for _, u := range users {
        names = append(names, u.Name)
    }
    return names
}

